import java.util.Random;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;

public class MultiThreadedMatrixMultiplication {
    private static final int MAX_VALUE = 10;
    private static final int MATRIX_SIZE = 4;
    private static final int NUM_THREADS = Runtime.getRuntime().availableProcessors();

    private static class MatrixMultiplyWorker implements Runnable {
        private final int[][] matrixA;
        private final int[][] matrixB;
        private final int[][] resultMatrix;
        private final int startRow;
        private final int endRow;

        public MatrixMultiplyWorker(int[][] matrixA, int[][] matrixB, int[][] resultMatrix, 
                                  int startRow, int endRow) {
            this.matrixA = matrixA;
            this.matrixB = matrixB;
            this.resultMatrix = resultMatrix;
            this.startRow = startRow;
            this.endRow = endRow;
        }

        @Override
        public void run() {
            for (int i = startRow; i < endRow; i++) {
                for (int j = 0; j < resultMatrix[0].length; j++) {
                    resultMatrix[i][j] = 0;
                    for (int k = 0; k < matrixB.length; k++) {
                        resultMatrix[i][j] += matrixA[i][k] * matrixB[k][j];
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        // Generate random matrices
        int[][] matrixA = generateRandomMatrix(MATRIX_SIZE, MATRIX_SIZE);
        int[][] matrixB = generateRandomMatrix(MATRIX_SIZE, MATRIX_SIZE);
        int[][] resultMatrix = new int[MATRIX_SIZE][MATRIX_SIZE];

        // Print the matrices
        System.out.println("Matrix A:");
        printMatrix(matrixA);
        System.out.println("\nMatrix B:");
        printMatrix(matrixB);

        // Perform multi-threaded matrix multiplication
        ExecutorService executor = Executors.newFixedThreadPool(NUM_THREADS);

        int rowsPerThread = MATRIX_SIZE / NUM_THREADS;
        int remainingRows = MATRIX_SIZE % NUM_THREADS;

        int startRow = 0;
        for (int i = 0; i < NUM_THREADS; i++) {
            int threadRows = rowsPerThread + (i < remainingRows ? 1 : 0);
            int endRow = startRow + threadRows;

            executor.execute(new MatrixMultiplyWorker(matrixA, matrixB, resultMatrix, startRow, endRow));
            startRow = endRow;
        }

        executor.shutdown();
        try {
            executor.awaitTermination(1, TimeUnit.MINUTES);
        } catch (InterruptedException e) {
            e.printStackTrace();
        }

        // Print the result
        System.out.println("\nResult Matrix (A × B):");
        printMatrix(resultMatrix);
    }

    private static int[][] generateRandomMatrix(int rows, int cols) {
        int[][] matrix = new int[rows][cols];
        Random random = new Random();

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                matrix[i][j] = random.nextInt(MAX_VALUE);
            }
        }

        return matrix;
    }

    private static void printMatrix(int[][] matrix) {
        for (int[] row : matrix) {
            for (int val : row) {
                System.out.print(val + "\t");
            }
            System.out.println();
        }
    }
}
