fn main() -> Result<(), Box<dyn Error>> {
    // Get the file path from arguments or use a default
    let args: Vec<String> = std::env::args().collect();
    let filepath = args.get(1).map(|s| s.as_str()).unwrap_or("input.txt");

    // Read the file
    let mut word_counts = HashMap::new();
    match read_file_and_count_words(filepath, &mut word_counts) {
        Ok(_) => {
            // Sort the words by count
            let mut counts: Vec<(&String, &u32)> = word_counts.iter().collect();
            counts.sort_by(|a, b| b.1.cmp(a.1));

            // Display the top 5 words (or fewer if there aren't 5 unique words)
            println!("Top words by frequency:");
            for (i, (word, count)) in counts.iter().take(5).enumerate() {
                println!("{}. \"{}\" - {} occurrences", i + 1, word, count);
            }
        }
        Err(e) => eprintln!("Error processing file: {}", e),
    }

    Ok(())
}

fn read_file_and_count_words(
    filepath: &str,
    word_counts: &mut HashMap<String, u32>,
) -> Result<(), Box<dyn Error>> {
    let path = Path::new(filepath);
    let file = File::open(path)?;
    let reader = BufReader::new(file);

    for line in reader.lines() {
        let line = line?;

        // Split the line into words and process each word
        for word in line.split_whitespace() {
            // Remove punctuation and convert to lowercase
            let clean_word: String = word
                .chars()
                .filter(|c| c.is_alphabetic() || c.is_numeric())
                .collect::<String>()
                .to_lowercase();

            if !clean_word.is_empty() {
                *word_counts.entry(clean_word).or_insert(0) += 1;
            }
        }
    }

    Ok(())
}
