#include <algorithm>
#include <type_traits>

// CRC-32 polynomial for IEEE 802.3 standard
constexpr uint32_t CRC32_POLYNOMIAL = 0xEDB88320;

// Generate CRC32 lookup table at compile time
constexpr std::array<uint32_t, 256> generate_crc32_table() {
    std::array<uint32_t, 256> table{};

    for (uint32_t i = 0; i < 256; ++i) {
        uint32_t crc = i;
        for (uint32_t j = 0; j < 8; ++j) {
            crc = (crc >> 1) ^ ((crc & 1) * CRC32_POLYNOMIAL);
        }
        table[i] = crc;
    }

    return table;
}

// Lookup table for CRC32 calculation
constexpr auto CRC32_TABLE = generate_crc32_table();

// Update CRC32 with a single byte
constexpr uint32_t update_crc32(uint32_t crc, uint8_t data) {
    return (crc >> 8) ^ CRC32_TABLE[(crc & 0xFF) ^ data];
}

// Calculate CRC32 for a fixed-size array at compile time
template<typename T, size_t N>
constexpr uint32_t crc32(const std::array<T, N>& data) {
    uint32_t crc = 0xFFFFFFFF;

    for (const auto& item : data) {
        const uint8_t* bytes = reinterpret_cast<const uint8_t*>(&item);
        for (size_t i = 0; i < sizeof(T); ++i) {
            crc = update_crc32(crc, bytes[i]);
        }
    }

    return ~crc;
}

// Utility to apply a transform and calculate CRC32 at compile time
template<typename T, size_t N, typename Func>
constexpr auto transform_and_crc32(const std::array<T, N>& input, Func&& func) {
    std::array<std::invoke_result_t<Func, T>, N> result{};

    for (size_t i = 0; i < N; ++i) {
        result[i] = func(input[i]);
    }

    return std::pair{result, crc32(result)};
}

// Example usage
constexpr std::array<int, 5> data = {1, 2, 3, 4, 5};
constexpr auto transformed_with_crc = transform_and_crc32(data, [](int x) { return x * 2; });
