            let data = TelemetryData {
                device_id,
                value: i as f64 * 0.1,
                timestamp: i as u64,
            };

            if tx.send(data).await.is_err() {
                break;
            }

            sleep(Duration::from_millis(10)).await;
        }
    });

    // Create telemetry processor with backpressure control
    let processor = TelemetryProcessor::new(5);

    // Convert mpsc receiver to a stream and process data
    let stream = stream::unfold(rx, |mut rx| async move {
        rx.recv().await.map(|data| (data, rx))
    });

    processor.process_telemetry(stream).await;
