// Function to render a Mandelbrot fractal using WebAssembly and TypedArray.map
async function renderFractal(width, height, maxIterations) {
  // Create WebAssembly module
  const { module, memory } = await createWasmModule();

  // Create result buffer
  const resultSize = width * height;
  const resultBuffer = new Uint32Array(memory.buffer, 0, resultSize);

  // Set fractal parameters
  const xMin = -2.0;
  const xMax = 1.0;
  const yMin = -1.5;
  const yMax = 1.5;

  // Compute the fractal using WebAssembly
  module.exports.compute_mandelbrot_simd(
    width, height, maxIterations,
    xMin, xMax, yMin, yMax,
    0 // Result buffer offset
  );

  // Use TypedArray.map to parallelize color mapping
  const colors = new Uint8ClampedArray(resultSize * 4);

  // Convert iteration counts to colors using TypedArray.map
  const colorArray = Array.from(resultBuffer).map((iterations) => {
    if (iterations === maxIterations) {
      return [0, 0, 0, 255]; // Black for points in the set
    } else {
      // Calculate color based on iterations
      const hue = (iterations / maxIterations * 360) % 360;
      const saturation = 100;
      const lightness = 50;

      // Convert HSL to RGB
      const c = (1 - Math.abs(2 * lightness / 100 - 1)) * saturation / 100;
      const x = c * (1 - Math.abs((hue / 60) % 2 - 1));
      const m = lightness / 100 - c / 2;

      let r, g, b;
      if (hue < 60) { r = c; g = x; b = 0; }
      else if (hue < 120) { r = x; g = c; b = 0; }
      else if (hue < 180) { r = 0; g = c; b = x; }
      else if (hue < 240) { r = 0; g = x; b = c; }
      else if (hue < 300) { r = x; g = 0; b = c; }
      else { r = c; g = 0; b = x; }

      return [
        Math.round((r + m) * 255),
        Math.round((g + m) * 255),
        Math.round((b + m) * 255),
        255
      ];
    }
  });

  // Flatten the color array into a Uint8ClampedArray for ImageData
  for (let i = 0; i < resultSize; i++) {
    const pixelColors = colorArray[i];
    const offset = i * 4;
    colors[offset] = pixelColors[0];     // R
    colors[offset + 1] = pixelColors[1]; // G
    colors[offset + 2] = pixelColors[2]; // B
    colors[offset + 3] = pixelColors[3]; // A
  }

  return colors;
}

