package com.example.processor;

import com.google.auto.service.AutoService;
import com.squareup.javapoet.*;

import javax.annotation.processing.*;
import javax.lang.model.SourceVersion;
import javax.lang.model.element.*;
import javax.lang.model.type.TypeMirror;
import javax.lang.model.util.Elements;
import javax.lang.model.util.Types;
import javax.tools.Diagnostic;
import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@SupportedAnnotationTypes("com.example.processor.GrpcService")
@SupportedSourceVersion(SourceVersion.RELEASE_8)
@AutoService(Processor.class)
public class GrpcServiceProcessor extends AbstractProcessor {

    private Types typeUtils;
    private Elements elementUtils;
    private Filer filer;
    private Messager messager;

    @Override
    public synchronized void init(ProcessingEnvironment processingEnv) {
        super.init(processingEnv);
        typeUtils = processingEnv.getTypeUtils();
        elementUtils = processingEnv.getElementUtils();
        filer = processingEnv.getFiler();
        messager = processingEnv.getMessager();
    }

    @Override
    public boolean process(Set<? extends TypeElement> annotations, RoundEnvironment roundEnv) {
        for (TypeElement annotation : annotations) {
            Set<? extends Element> annotatedElements = roundEnv.getElementsAnnotatedWith(annotation);

            Map<Boolean, List<Element>> partitioned = annotatedElements.stream()
                    .collect(Collectors.partitioningBy(e -> e.getKind() == ElementKind.INTERFACE));

            List<Element> interfaces = partitioned.get(true);
            List<Element> notInterfaces = partitioned.get(false);

            notInterfaces.forEach(e -> 
                messager.printMessage(Diagnostic.Kind.ERROR, 
                    "@GrpcService can only be applied to interfaces", e)
            );

            interfaces.forEach(this::generateGrpcStub);
        }
        return true;
    }

    private void generateGrpcStub(Element element) {
        TypeElement typeElement = (TypeElement) element;
        String packageName = elementUtils.getPackageOf(typeElement).getQualifiedName().toString();
        String className = typeElement.getSimpleName().toString();
        String stubClassName = className + "GrpcStub";

        // Collect all methods for the service interface
        List<ExecutableElement> methods = elementUtils.getAllMembers(typeElement).stream()
                .filter(e -> e.getKind() == ElementKind.METHOD)
                .filter(e -> !e.getModifiers().contains(Modifier.STATIC))
                .filter(e -> e instanceof ExecutableElement)
                .map(e -> (ExecutableElement) e)
                .collect(Collectors.toList());

        // Generate stub implementation
        TypeSpec.Builder classBuilder = TypeSpec.classBuilder(stubClassName)
                .addModifiers(Modifier.PUBLIC)
                .addSuperinterface(TypeName.get(typeElement.asType()))
                .addField(FieldSpec.builder(
                        ClassName.get("io.grpc.stub", "AbstractStub"), 
                        "stub", 
                        Modifier.PRIVATE, Modifier.FINAL)
                        .build())
                .addMethod(MethodSpec.constructorBuilder()
                        .addModifiers(Modifier.PUBLIC)
                        .addParameter(ClassName.get("io.grpc.Channel", "channel"), "channel")
                        .addStatement("this.stub = new $T(channel)", 
                                ClassName.get(packageName, className + "Grpc", className + "Stub"))
                        .build());

        // Generate methods for each interface method
        methods.forEach(method -> {
            String methodName = method.getSimpleName().toString();
            TypeMirror returnType = method.getReturnType();
            List<? extends VariableElement> parameters = method.getParameters();

            MethodSpec.Builder methodBuilder = MethodSpec.methodBuilder(methodName)
                    .addAnnotation(Override.class)
                    .addModifiers(Modifier.PUBLIC)
                    .returns(TypeName.get(returnType));

            // Add parameters
            parameters.forEach(param -> 
                methodBuilder.addParameter(
                    TypeName.get(param.asType()), 
                    param.getSimpleName().toString())
            );

            // Generate method body - this is simplified, real implementation would map types
            if (!returnType.toString().equals("void")) {
                methodBuilder.addStatement("$T request = $T.newBuilder()" +
                        parameters.stream()
                            .map(p -> ".set" + capitalize(p.getSimpleName().toString()) + 
                                  "(" + p.getSimpleName().toString() + ")")
                            .collect(Collectors.joining()) +
                        ".build()", 
                        ClassName.get(packageName, capitalize(methodName) + "Request"),
                        ClassName.get(packageName, capitalize(methodName) + "Request"));

                methodBuilder.addStatement("$T response = (($T) stub).blocking$L(request)", 
                        ClassName.get(packageName, capitalize(methodName) + "Response"),
                        ClassName.get(packageName, className + "Grpc", className + "BlockingStub"),
                        capitalize(methodName));

                methodBuilder.addStatement("return response.getResult()");
            } else {
                methodBuilder.addStatement("$T request = $T.newBuilder()" +
                        parameters.stream()
                            .map(p -> ".set" + capitalize(p.getSimpleName().toString()) + 
                                  "(" + p.getSimpleName().toString() + ")")
                            .collect(Collectors.joining()) +
                        ".build()", 
                        ClassName.get(packageName, capitalize(methodName) + "Request"),
                        ClassName.get(packageName, capitalize(methodName) + "Request"));

                methodBuilder.addStatement("(($T) stub).blocking$L(request)", 
                        ClassName.get(packageName, className + "Grpc", className + "BlockingStub"),
                        capitalize(methodName));
            }

            classBuilder.addMethod(methodBuilder.build());
        });

        // Write the class file
        try {
            JavaFile.builder(packageName, classBuilder.build())
                    .build()
                    .writeTo(filer);
        } catch (IOException e) {
            messager.printMessage(Diagnostic.Kind.ERROR, 
                "Error writing stub for " + className + ": " + e.getMessage());
        }
    }

    private String capitalize(String str) {
        return str.substring(0, 1).toUpperCase() + str.substring(1);
    }
}

