        int controlMask = 1 << u_controlQubit;
        shouldApplyGate = (stateIndex & controlMask) != 0 && (stateIndex & mask) != 0;
      } else {
        shouldApplyGate = true;
      }

      if (shouldApplyGate) {
        // Apply appropriate gate
        if (u_gateType == 0) {  // Hadamard
          outputState = applyHadamard(inputState);
        } else if (u_gateType == 1) {  // PauliX
          outputState = applyPauliX(inputState);
        } else if (u_gateType == 2) {  // Rotation
          outputState = applyRotation(inputState, 0.1);  // Example theta value
        } else {
          outputState = inputState;  // Identity
        }
      } else {
        outputState = inputState;
      }

      gl_FragColor = vec4(outputState, 0.0, 1.0);
    }
  )";

