  void* result_data;
  napi_create_typedarray(env, napi_float32_array, length, arraybuffer, 0, &result_typed_array);

  // Map function using WebGL shader
  napi_value map_fn_name, map_result;
  napi_create_string_utf8(env, "map", NAPI_AUTO_LENGTH, &map_fn_name);

  // Create mapping callback that will utilize WebGL
  napi_value mapping_args[1];
  napi_create_object(env, &mapping_args[0]);

  // Add shader code and parameters to the mapping object
  napi_value shader_val;
  napi_create_string_utf8(env, shader_code, NAPI_AUTO_LENGTH, &shader_val);
  napi_set_named_property(env, mapping_args[0], "shaderCode", shader_val);

  // Call the map method on the TypedArray
  napi_call_method(env, args[0], map_fn_name, 1, mapping_args, &map_result);

