import org.reactivestreams.Publisher;
import org.reactivestreams.Subscriber;
import org.reactivestreams.Subscription;

import java.io.IOException;
import java.util.concurrent.Flow;
import java.util.concurrent.SubmissionPublisher;
import java.util.concurrent.atomic.AtomicLong;

public class GraalVMJSONataMongoReactiveService {

    private final MongoClient mongoClient;
    private final Context polyglotContext;

    public GraalVMJSONataMongoReactiveService(String mongoConnectionString) {
        this.mongoClient = MongoClients.create(mongoConnectionString);
        this.polyglotContext = Context.newBuilder("js")
                .allowAllAccess(true)
                .build();

        try {
            // Initialize JSONata in the GraalVM JavaScript context
            polyglotContext.eval(Source.newBuilder("js", 
                    "var global = this; " +
                    "var module = {}; " +
                    "var exports = {};", "jsonata_setup.js").build());

            // Load JSONata library (assuming it's available in the classpath)
            polyglotContext.eval(Source.newBuilder("js", 
                    getClass().getClassLoader().getResource("jsonata.js")).build());
        } catch (IOException e) {
            throw new RuntimeException("Failed to initialize JSONata", e);
        }
    }

    public SubmissionPublisher<Document> createMappingService(
            String database,
            String collection,
            String jsonataExpression,
            int maxSubscribers) {

        // Prepare JSONata expression
        Value jsonataCompile = polyglotContext.eval("js", "jsonata");
        Value compiledExpression = jsonataCompile.execute(jsonataExpression);

        // Create reactive streams publisher
        SubmissionPublisher<Document> resultPublisher = 
                new SubmissionPublisher<>(
                        java.util.concurrent.ForkJoinPool.commonPool(),
                        maxSubscribers);

        // Get MongoDB collection
        MongoDatabase db = mongoClient.getDatabase(database);
        MongoCollection<Document> coll = db.getCollection(collection);

        // Create and subscribe to the change stream
        Publisher<ChangeStreamDocument<Document>> publisher = coll.watch();
        publisher.subscribe(new Subscriber<ChangeStreamDocument<Document>>() {
            private Subscription subscription;
            private final AtomicLong demand = new AtomicLong(0);

            @Override
            public void onSubscribe(Subscription s) {
                this.subscription = s;
                // Initial request
                subscription.request(1);
                demand.incrementAndGet();
            }

            @Override
            public void onNext(ChangeStreamDocument<Document> changeDoc) {
                demand.decrementAndGet();

                try {
                    // Convert MongoDB document to JSON string
                    String docJson = changeDoc.getFullDocument().toJson();

                    // Apply JSONata transformation
                    Value input = polyglotContext.eval("js", "(" + docJson + ")");
                    Value result = compiledExpression.execute(input);

                    // Convert result to MongoDB Document
                    Document transformedDoc = Document.parse(result.toString());

                    // Apply backpressure: check if we can emit
                    long bufferedItems = resultPublisher.getNumberOfSubscribers() == 0 ? 0 :
                            resultPublisher.estimateMaximumLag();

                    if (bufferedItems < maxSubscribers) {
                        resultPublisher.submit(transformedDoc);
                    }

                } catch (Exception e) {
                    // Handle transformation errors
                    System.err.println("Error processing document: " + e.getMessage());
                } finally {
                    // Request next item with backpressure
                    if (resultPublisher.getNumberOfSubscribers() > 0 && 
                            demand.get() < maxSubscribers / 2) {
                        long toRequest = maxSubscribers - demand.get();
                        subscription.request(toRequest);
                        demand.addAndGet(toRequest);
                    } else {
                        subscription.request(1);
                        demand.incrementAndGet();
                    }
                }
            }

            @Override
            public void onError(Throwable t) {
                resultPublisher.closeExceptionally(t);
            }

            @Override
            public void onComplete() {
                resultPublisher.close();
            }
        });

        return resultPublisher;
    }

    public void close() {
        polyglotContext.close();
        mongoClient.close();
    }

